 1→// components/layout/PageHeader.tsx
 2→// Standardized page header for all pages
 3→
 4→import React from 'react';
 5→
 6→interface PageHeaderProps {
 7→  title: string;
 8→  description?: string;
 9→  action?: {
10→    label: string;
11→    onClick: () => void;
12→    icon?: React.ElementType;
13→  };
14→}
15→
16→export default function PageHeader({ title, description, action }: PageHeaderProps) {
17→  const ActionIcon = action?.icon;
18→
19→  return (
20→    <div className="border-b border-slate-800 -mx-6 md:-mx-8 -mt-6 md:-mt-8 mb-6">
21→      <div className="px-6 md:px-8 py-5 flex items-center justify-between">
22→        <div>
23→          <h1 className="text-2xl font-semibold text-white tracking-tight">{title}</h1>
24→          {description && (
25→            <p className="text-sm text-slate-400 mt-1">{description}</p>
26→          )}
27→        </div>
28→        {action && (
29→          <button
30→            onClick={action.onClick}
31→            className="ml-auto bg-white text-black rounded-lg px-4 py-2 text-sm font-medium hover:bg-gray-200 transition-colors flex items-center gap-2"
32→          >
33→            {ActionIcon && <ActionIcon size={16} />}
34→            {action.label}
35→          </button>
36→        )}
37→      </div>
38→    </div>
39→  );
40→}
