250→          {/* Competitors & Improvements */}
251→          <div className="grid md:grid-cols-2 gap-6">
252→            {result.competitorsMentioned.length > 0 && (
253→              <div className="ninja-card p-6">
254→                <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
255→                  <Users size={14} className="text-red-400" /> Concurrents mentionnés
256→                </h3>
257→                <div className="flex flex-wrap gap-2">
258→                  {result.competitorsMentioned.map((comp, i) => (
259→                    <span key={i} className="px-3 py-1.5 bg-red-500/5 border border-red-500/10 rounded-lg text-xs text-red-300 font-medium">
260→                      {comp}
261→                    </span>
262→                  ))}
263→                </div>
264→              </div>
265→            )}
266→            <div className="ninja-card p-6">
267→              <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
268→                <Lightbulb size={14} className="text-amber-400" /> Comment améliorer votre visibilité
269→              </h3>
270→              <ul className="space-y-2">
271→                {result.improvements.map((imp, i) => (
272→                  <li key={i} className="flex items-start gap-2 text-sm text-gray-400">
273→                    <span className="text-purple-400 mt-0.5 shrink-0">→</span>
274→                    {imp}
275→                  </li>
276→                ))}
277→              </ul>
278→            </div>
279→          </div>
280→        </div>
281→      )}
282→
283→      {/* Empty State */}
284→      {!result && !isSimulating && (
285→        <div className="ninja-card p-12 flex flex-col items-center justify-center text-center">
286→          <div className="flex items-center gap-3 mb-6">
287→            {Object.entries(ENGINE_STYLES).map(([name, style]) => (
288→              <div key={name} className={`w-14 h-14 rounded-xl ${style.bg} flex flex-col items-center justify-center gap-1`}>
289→                <MessageSquare size={18} className={style.color} />
290→                <span className={`text-[8px] font-bold ${style.color}`}>{name.slice(0, 3)}</span>
291→              </div>
292→            ))}
293→          </div>
294→          <h3 className="text-lg font-bold text-gray-300 mb-2">Simulateur de Citation</h3>
295→          <p className="text-sm text-gray-500 max-w-md">Posez une question et découvrez si ChatGPT, Claude, Perplexity, Gemini et AI Overviews mentionneraient votre marque dans leur réponse</p>
296→        </div>
297→      )}
298→    </div>
299→  );
300→};
301→
302→export default AiCitationSimulator;
303→

